#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
typedef long long LL;
inline int read()
{
	int res(0);char ch(getchar());bool flag(false);while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return flag ? -res : res ;
}
inline LL min(const LL &x,const LL &y){return x<y?x:y;}
inline void chkmax(int &x,const int &w){x<w?x=w:0;} 
typedef long long LL;const int N=1e5+10;LL a[N],dp[N],b[N];int mx[N*10<<2],n,Mx,h[N];
inline LL Cnt(const int &p,const LL &x){return a[p]*x+b[p];}
inline void add(int pos,const int &l=0,const int &r=Mx,const int &cur=1)
{
	if(l==r){if(Cnt(pos,l)<Cnt(mx[cur],l))mx[cur]=pos;return;} const int &mid=(l+r)>>1;
	if(Cnt(pos,mid)<Cnt(mx[cur],mid)){int tmp(pos);pos=mx[cur];mx[cur]=tmp;}
	if(Cnt(pos,l)<Cnt(mx[cur],l))add(pos,l,mid,cur<<1);else if(Cnt(pos,r)<Cnt(mx[cur],r))add(pos,mid+1,r,cur<<1|1); 
}
inline LL qry(const int &H,const int &l=0,const int &r=Mx,const int &cur=1)
{
	if(l==r)return Cnt(mx[cur],H);const int &mid=(l+r)>>1;
	return min(Cnt(mx[cur],H),H<=mid?qry(H,l,mid,cur<<1):qry(H,mid+1,r,cur<<1|1));
}
int main()
{
	n=read();rep(1,n,i)chkmax(Mx,h[i]=read());b[0]=4e18;LL S=0;
	a[1]=-2*h[1];b[1]=1ll*h[1]*h[1]-(S=read());add(1);
	rep(2,n,i)
	{
		dp[i]=1ll*h[i]*h[i]+S+qry(h[i]);S+=read();
		a[i]=-2*h[i];b[i]=dp[i]+1ll*h[i]*h[i]-S;add(i);
	}
	printf("%lld\n",dp[n]);
}
